VALUES
  ('locality-d0d1b9a2-moex-00214', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司在X3年至X5年間的財務資料有下述錯誤事項： ㉑期末漏作預收收入之調整分錄（下一年度實現），X3年 $30,500；X4年 $37,000；X5年$46,000。 ㉒期末漏作應付租金之調整分錄（下一年度實現），X3年$42,000；X4年正確無誤；X5年$37,000。 ㉓X5年以$33,000出售已提盡折舊之設備，此交易之分錄漏作。 ㉔期末存貨X3年多計$57,000；X4年少計$69,000；X5年正確無誤。 假設上述錯誤於X5年結帳前發現，且不考慮所得稅影響。試問X5年度淨利高估或低估多少？', '["高估$82,000", "低估$82,000", "低估$115,000", "高估$115,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00215', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司有關確定福利計畫之相關資料如下，折現率為9%： X1年底調整後相關項目金額 X2年相關資料 淨確定福利負債 $332,000 當期服務成本 $ 388,000 確定福利義務現值 910,000 提撥基金 400,000 計畫資產公允價值 578,000 支付確定福利 160,000 期末確定福利義務現值應有餘額 1,240,000 期末計畫資產之公允價值 883,000 期初修改計畫發生前期服務成本 56,000 試計算X2年度之確定福利計畫再衡量數為何？', '["利益$7,120", "利益$12,980", "利益$53,920", "利益$65,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00216', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X3年度淨利$750,000，普通股全年流通在外股數為200,000股。X3年初有流通在外 認股權15,000單位，每單位得按每股$40認購普通股1股，截至年底尚未執行。此外，X3年 1月1日公司發行員工股票選擇權10,000股，員工於服務滿4年後，每單位得按每股$30認 購普通股1股，發行日每單位員工股票選擇權之公允價值為$15，X3年12月31日員工尚須 提供服務之每股公允價值為$12。甲公司普通股全年平均市價為$48。試問甲公司 X3 年稀釋 每股盈餘為何？', '["$3.64", "$3.68", "$3.69", "$3.70"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00217', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲牧場於X1年初以$220,000購買40頭乳牛，另支付$10,000運費，準備飼養成熟後用來生 產牛乳。甲牧場估計若立即出售此批乳牛，將須負擔運送到市場的成本為$15,000及市場管理 費為$6,000，試問甲牧場原始認列該生物資產應認列之費損金額為何？', '["$0", "$10,000", "$21,000", "$31,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00218', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '下列有關財務報表觀念之敘述，何者正確？', '["出售庫藏股票損失應認列為費損", "符合財務報表要素定義之項目，即應予以認列", "財務報表要素之衡量基礎，一經決定即不可改變", "當 IASB 財務報表觀念架構與國際財務報導準則規定發生衝突時，應以國際財務報導準則 為準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00219', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X10年初以$10,000,000取得某煤礦，並另支付無形開發成本$1,000,000，估計煤的蘊 藏量為1,000,000噸，開採完後須支付$2,000,000將土地復原，X10年度的開採量及銷售量分 別為300,000噸及200,000噸。X11年初甲公司重新評估時發現煤的總蘊藏量為800,000噸， X11年度的開採量及銷售量分別為200,000噸及300,000噸。煤每噸的售價為$25，加工成本 為$3，銷售費用為$2。則甲公司X11年度的銷貨毛利為：', '["$2,700,000", "$2,417,500", "$1,060,000", "$1,660,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00220', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X2年7月1日獲得政府對某個4年期專案計畫的補助款$60,000,000，該數額占整 個專案計畫支出之 50%。甲公司於 X2 年及 X3 年執行該專案累計已投入專案活動之支出為 $90,000,000。X3年底甲公司因未符合附帶條件而遭要求退還全部之政府補助款，試問此退還 事件對甲公司X3年稅前淨利的影響為何？', '["無影響", "減少$22,500,000", "減少$45,000,000", "減少$60,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00221', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司與乙公司簽訂不可取消之銷貨合約，約定於X1年10月1日至X2年3月31日間，以 每單位$22的價格銷售80,000單位商品給乙公司。甲公司於X1年度已銷售30,000單位。X1 年底甲公司庫存商品數量為40,000單位，每單位成本為$19，當日之單位重置成本為$20。該 商品於銷售給乙公司時，甲公司尚需負擔之銷售費用為售價的15%，試問甲公司於X1年底 應認列與此銷貨合約有關的費損金額為何？', '["$0", "$12,000", "$15,000", "$25,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00222', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於 X10 年 5 月 1 日以完全追索權方式，出售帳面金額$2,500,000 之應收帳款予乙銀 行，乙銀行負責收款，但銷貨退回、折扣、讓價仍由甲公司負責，故乙銀行保留10%以供沖 抵可能發生之銷貨退回、讓價及折扣。乙銀行另收取應收帳款總額5%之手續費，5月份共計 發生銷貨退回$70,000，銷貨讓價$10,000，並發生呆帳$55,000。另外，甲公司帳上於X10年 4月30日前已對此項帳款估列備抵呆帳$40,000。有關應收帳款移轉之會計處理，下列敘述何 者正確？', '["甲公司在5月1日應貸記應收帳款$2,500,000", "甲公司對此項應收帳款之移轉交易整體共收到現金為$2,240,000", "甲公司在5月份應認列呆帳費用$55,000", "甲公司在5月1日應認列出售帳款損失$125,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00223', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年底營業活動淨現金流入為$450,000，本期賒銷之銷貨收入$100,000，應收帳款收 現$80,000，沖銷無法收回之帳款$5,000，提列預期信用減損損失$10,000，折舊費用$25,000， 應付公司債折價攤銷$13,000，遞延所得稅負債增加$15,000，應付股利增加$60,000，採權益法 認列之關聯企業損失份額$80,000，利息費用$27,000，宣告股利$120,000。因利息及股利在現 金流量表各有不同活動歸類選項，請問甲公司X1年度淨利不可能為下列何者？', '["$313,000", "$327,000", "$373,000", "$388,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "79dbd7193b47", "answer_pdf_sha1": "2817fe9caeb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1710", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
